import{_ as s,o as t,c as r,ag as i}from"./chunks/framework.ETe_P6d1.js";const a="/kaiping-reports/assets/1.CiCuneGA.jpg",o="/kaiping-reports/assets/2.BSdwhA3j.jpg",e="/kaiping-reports/assets/3.DLcyFL0A.jpg",_="/kaiping-reports/assets/4.CDVJjZMT.jpg",g="/kaiping-reports/assets/5.4vNxfl9k.jpg",n="/kaiping-reports/assets/6._rutpwQp.jpg",c="/kaiping-reports/assets/7.pzAb4FcP.jpg",m="/kaiping-reports/assets/8.DoSfaIl0.jpg",l="/kaiping-reports/assets/9.DoFa5PSj.jpg",k="/kaiping-reports/assets/10.kqLYXUbm.jpg",j="/kaiping-reports/assets/11.B34vTkA0.jpg",d="/kaiping-reports/assets/12.Cek-lN85.jpg",f="/kaiping-reports/assets/13.Bx80Po7J.jpg",D="/kaiping-reports/assets/14.CJIyo5fC.jpg",u="/kaiping-reports/assets/15.CUZaj-5C.jpg",C="/kaiping-reports/assets/16.DCv3rUj8.jpg",h="/kaiping-reports/assets/17.w62-wBh3.jpg",B="/kaiping-reports/assets/18.DDrY6TUX.jpg",T="/kaiping-reports/assets/19.xypfsHED.jpg",A="/kaiping-reports/assets/20.DVMaM4nJ.jpg",P="/kaiping-reports/assets/21.q-Bu0BEp.jpg",S="/kaiping-reports/assets/22.BuwUlVQ9.jpg",b=JSON.parse('{"title":"关于开平装饰符号与文化表达调研报告","description":"","frontmatter":{"title":"关于开平装饰符号与文化表达调研报告"},"headers":[],"relativePath":"reports/郑淙睿/郑淙睿_调研报告.md","filePath":"reports/郑淙睿/郑淙睿_调研报告.md"}'),x={name:"reports/郑淙睿/郑淙睿_调研报告.md"};function J(V,p,v,w,M,N){return t(),r("div",null,[...p[0]||(p[0]=[i('<p>关于开平装饰符号与文化表达调研报告</p><h1 id="关于开平装饰符号与文化表达调研报告" tabindex="-1">关于开平装饰符号与文化表达调研报告 <a class="header-anchor" href="#关于开平装饰符号与文化表达调研报告" aria-label="Permalink to &quot;关于开平装饰符号与文化表达调研报告&quot;">​</a></h1><p>开平位于广东西南部，水网密布、侨务活动频繁。自明清时期起，尤其是20世纪初，大量开平人远赴美国、加拿大、澳大利亚及东南亚各国谋生，事业有成后返乡修建住宅、祠堂与商业建筑。在海外建筑文化熏陶与本土传统建筑规制的双重影响下，开平建筑逐渐形成“中式为体、西式为用”的独特风格，装饰艺术更是融合岭南传统工艺与西方装饰技法，成为世界文化遗产“开平碉楼与村落”最具魅力的部分。本文选取立园（私家园林别墅）、仓东村（古村祠堂民居）、塘口墟（墟市公共建筑）、赤坎古镇（骑楼商业街）四类代表性场景，结合实地调研与文献梳理，剖析开平建筑装饰的构成、特征与文化表达，为侨乡建筑文化的保护与传承提供参考。</p><p>开平建筑装饰的核心特点，是多元文化元素的有机融合与本土文化内核的坚守，并非简单的元素堆砌，而是基于实用需求、审美偏好与文化认同的深度结合，在结构形制、构件装饰、工艺技法上均有清晰体现。</p><p>（一）结构形制：中式骨架与西式表皮的共生</p><p>中式屋顶与西式柱式的经典搭配中式传统屋顶（硬山顶、悬山顶、重檐顶）与西方古典柱式（罗马多立克柱、爱奥尼柱、科林斯柱）结合，是开平建筑最常见的融合形式。中式瓦顶以青瓦、琉璃瓦铺设，装饰龙脊、吻兽、镬耳山墙，保留岭南建筑隔热、排水、祈福的功能与寓意；西式柱式多用于楼身、门廊、阳台，兼具支撑与装饰作用，让建筑更显挺拔大气。立园泮立楼建于1926年，楼顶为中式重檐绿琉璃瓦顶，飞檐翘角、龙脊蜿蜒，带有传统宫殿韵味；楼身三层均采用古罗马式圆柱，柱头雕刻卷草纹，支撑外挑阳台，黄墙、绿瓦与白色柱身形成强烈视觉对比，风格鲜明。</p><p><img src="'+a+'" alt="图1：立园琉璃瓦穹顶"></p><p>西式拱券与岭南灰塑的工艺混搭西式半圆拱、尖拱广泛应用于门窗、廊檐，边缘常装饰巴洛克涡卷纹与浮雕；而拱券上方、山墙、屋脊等位置，则以岭南传统灰塑装饰，形成“西式结构+中式装饰”的独特组合。灰塑以石灰为主要原料，耐酸碱、抗风雨，十分适配开平湿热的气候，题材既包含传统吉祥纹样，也融入西方装饰图案。仓东村谢氏祠堂正门采用西式半圆拱券，券边雕刻简洁线脚与花卉纹样；拱券上方的门楣、山墙处，用灰塑塑造“双凤朝阳”“福禄寿”等图案，以蓝、绿、白为主色调，线条灵动，与硬朗的拱券形成刚柔相济的美感。</p><p>（二）构件装饰：本土工艺与西方元素的互嵌</p><p>建筑细部构件同样呈现中西融合的特点：中式木雕、砖雕、石雕，与西式铁艺、彩色玻璃、水泥浮雕相互搭配；传统吉祥构件与西方几何纹、卷草纹、人物纹样穿插出现，自然协调。</p><p><img src="'+o+'" alt="图2：立园科林斯柱廊"></p><p><img src="'+e+'" alt="图3：立园灰塑文字"></p><p><img src="'+_+'" alt="图4：仓东村金属百叶窗"></p><p>门窗体系：赤坎古镇骑楼多采用西式拱窗、矩形窗，窗框用水泥制作巴洛克山花，窗扇镶嵌进口彩色玻璃，以红、蓝、黄几何纹样为主；同时保留中式蚝壳窗、木格窗，部分窗棂雕刻回字纹、盘长纹，兼顾通风、采光与装饰效果。</p><p>赤坎古镇门窗照片 赤坎古镇门窗照片 赤坎古镇彩色玻璃</p><p><img src="'+g+'" alt="图5：仓东村民居墙体"></p><p><img src="'+n+'" alt="图6：仓东村拱券装饰"></p><p>阳台与栏杆：塘口墟民国商业建筑的阳台使用西式铸铁栏杆，线条流畅、呈几何卷曲造型；栏杆立柱顶端装饰中式小石狮、花卉石雕，西方工艺的精致与中式雕刻的古朴相互映衬，别具特色。</p><p>开平建筑雕刻以灰塑、木雕、石雕、砖雕、水泥雕为主要工艺，题材涵盖吉祥动植物、传统人文故事、西方几何与器物、文字符号四大类，按照建筑空间等级分布在不同位置，形成完整的符号叙事体系。</p><p>（一）动植物题材：祈福纳祥的核心载体</p><p>动植物题材在装饰中占比最高，以中式传统吉祥纹样为主，部分融入西方花卉、动物元素，多布置在屋脊、门楣、山墙、栏杆等醒目位置。</p><p>中式传统吉祥动植物瑞兽以龙、凤、麒麟、狮子、鹿、鹤最为常见，龙、凤装饰在屋顶龙脊、殿堂正脊，象征尊贵与吉祥；狮子雕刻在门墩、柱头，寓意驱邪守护；鹤、鹿搭配松、竹，表达“松鹤延年”“鹿鹤同春”的长寿愿景。立园泮立楼屋脊装饰陶塑龙纹，仓东村民居门墩雕刻石狮，都带有浓郁的岭南特色。禽鸟花卉以喜鹊、鸳鸯、蝙蝠、牡丹、莲花、梅兰竹菊为经典组合，“喜鹊登梅”寓意喜上眉梢，“鸳鸯戏水”象征夫妻和睦，“蝙蝠”谐音“福”，常与“寿”字组合成“五福捧寿”，开平灰塑中“双凤朝阳”“鸟语花香”题材数量众多，色彩鲜艳、立体感强。</p><p>西方动植物元素受西方建筑装饰影响，卷草纹、棕榈叶、玫瑰花、葡萄纹等题材逐渐出现，多以浮雕形式呈现在西式柱身、拱券、山花上。赤坎古镇骑楼山花雕刻葡萄纹，寓意多子多福，成为华侨海外生活记忆的视觉符号。</p><p><img src="'+c+'" alt="图7：塘口墟骑楼现状"></p><p><img src="'+m+'" alt="图8：塘口墟天下粮仓先锋书店"></p><p><img src="'+l+'" alt="图9：赤坎古镇骑楼装饰"></p><p>（二）几何纹与器物题材：秩序与异域的视觉表达</p><p>几何纹样中式回字纹、万字纹、盘长纹、冰裂纹，与西方菱形纹、圆形纹、波浪纹、螺旋纹搭配使用，多用于窗棂、栏杆、腰线、地面铺装。中式几何纹寓意福寿绵长、生生不息；西方几何纹注重对称与韵律，强化建筑的现代感与秩序感。立园室内意大利水磨石地面，用红、白、黑三色拼接出圆形、方形组合纹样，既符合西式审美，又暗含中式“天圆地方”的寓意。</p><p><img src="'+k+'" alt="图10：批量复制的吉祥符号"></p><p><img src="'+j+'" alt="图11：立园地面铺砖"></p><p>立园碉楼万字几何纹 赤坎古镇太阳形纹案</p><p>器物题材中式器物题材包含博古纹（花瓶、香炉、书画、如意）、暗八仙（八仙法器），体现文人雅致与祈福愿景；西方题材则有西洋钟表、留声机、轮船、火车、西洋花瓶等，直观记录近代工业文明与华侨的海外经历。塘口墟某民国碉楼山墙，用灰塑塑造轮船、火车图案，见证了华侨跨洋谋生的历史。</p><p>（三）文字与人文题材：伦理与叙事的文化传递</p><p>文字符号文字符号以吉祥汉字、匾额对联、姓氏标识为主，分布在门楣、牌匾、照壁、柱头等处，常见“福、禄、寿、喜、吉、祥”等字，以及“本立道生”“耕读传家”等格言。立园大牌坊题写“立园”，别墅区牌楼题写“本立道生”，传递儒家伦理与家国情怀；赤坎古镇骑楼商铺匾额多为中式书法，搭配西式边框，实现文化与商业的融合。</p><p>人文故事题材人文故事以岭南传统戏曲、历史典故、神话传说为主，多通过木雕、灰塑呈现在厅堂、门楣、照壁，承担道德教化与文化传承的作用。立园泮立楼一楼门楣灰塑“刘备三顾茅庐”，二楼潮州涂金樟木雕“六国大封相”，人物形象生动、工艺精湛，弘扬忠义、礼贤的传统价值观；部分建筑还装饰“八仙过海”“麻姑献寿”等神话题材，寄托超凡脱俗的美好愿望。</p><p>（四）题材分布规律</p><p><img src="'+d+'" alt="图12：碉楼万字几何纹"></p><p><img src="'+f+'" alt="图13：赤坎古镇太阳形纹案"></p><p>开平建筑装饰题材遵循“外简内繁、上吉下祥、主重次轻”的分布原则，在建筑外部（屋顶、山墙、外墙）以瑞兽、花卉、几何纹等简洁醒目的题材为主，兼顾祈福与视觉效果；在建筑内部（厅堂、梁架、门窗）以人物故事、精致木雕、博古纹为主，凸显文化内涵与工艺水平；重要位置（正门、正脊、主厅）题材繁复、工艺精湛；次要位置（侧门、厢房、围墙）：题材简洁、工艺简化。</p><p>（一）立园：私家园林的中西合璧典范</p><p>立园是华侨私家园林别墅，以泮立楼、泮文楼为核心，装饰遍布屋顶、楼身柱廊、门楣、室内天花、地面。屋顶采用中式重檐绿琉璃瓦、龙脊、吻兽，尽显传统皇家风格；楼身搭配古罗马爱奥尼柱、巴洛克窗饰，尽显西方古典韵味；门楣与室内有灰塑历史故事、潮州涂金木雕，彰显岭南传统工艺；地面、天花采用意大利水磨石、东洋式天花，实现多元风格融合。立园的装饰以中式园林为灵魂、西式建筑为外形，既传递孝悌、忠义的儒家伦理，又展现海外视野与现代生活追求，是华侨“家国同构”文化的生动缩影。</p><p><img src="'+D+'" alt="图14：立园泮立楼"></p><p><img src="'+u+'" alt="图15：仓东村祠堂"></p><p><img src="'+C+'" alt="图16：塘口墟碉楼"></p><p>（二)仓东村：古村祠堂的传统与西式融合</p><p><img src="'+h+'" alt="图17：赤坎古镇立面"></p><p><img src="'+B+'" alt="图18：赤坎古镇街景1"></p><p><img src="'+T+'" alt="图19：赤坎古镇街景2"></p><p>仓东村是拥有700年历史的古村，装饰集中在谢氏祠堂与传统民居的正门拱券、山墙、屋脊、门墩、窗棂。谢氏祠堂采用西式半圆拱券，搭配中式灰塑“双凤朝阳”“福禄寿”，实现中西工艺混搭；民居以青砖墙体、石雕门墩、木格窗为主，以传统风格为核心，仅局部点缀西式元素。作为宗族聚居地，仓东村以中式宗族礼制为核心，西式元素仅作装饰补充，体现华侨“根在本土、艺融西方”的文化坚守，是古村侨化的温和样本。</p><p>（三）塘口墟：墟市建筑的实用主义融合</p><p>塘口墟以民国墟市商业建筑、碉楼为主，装饰分布在骑楼廊柱、阳台栏杆、山花、碉楼射击孔周边。商业建筑采用西式铸铁栏杆、水泥山花、西方卷草纹，搭配中式柱头石狮、灰塑吉祥字；碉楼以红砖、青砖为主体，搭配简约西式拱窗，射击孔周边装饰几何石雕，整体装饰简洁、注重实用。塘口墟的装饰适配商贸与防御需求，秉持“简洁实用、中西互补”的理念，体现侨乡墟市的“功利性审美”，记录了近代开平商贸发展与防御需求。</p><p>（四）赤坎古镇：骑楼商业街的异域风情融合</p><p><img src="'+A+'" alt="图20：立园建筑细节"></p><p><img src="'+P+'" alt="图21：仓东村装饰细节"></p><p><img src="'+S+'" alt="图22：塘口墟骑楼"></p><p>赤坎古镇拥有680余座骑楼，形成绵延3公里的商业街，装饰集中在骑楼山花、拱窗、柱廊、商铺牌匾、彩色玻璃。外立面以巴洛克涡卷山花、罗马柱、哥特尖顶元素为主，西方风格浓郁；细部保留中式镬耳墙、蚝壳窗、灰塑吉祥纹、书法匾额，实现“西式为表、中式为里”。作为商贸重镇，赤坎骑楼装饰既以异域风情吸引客流、展现西方时尚，又坚守岭南商业文化与家族传统，是华侨商业文化与异域审美融合的极致体现。</p><p>（一）核心文化内涵</p><p>开平建筑中的装饰符号是华侨跨文化经历的物化呈现，是华侨文化的活态载体：西方元素记录海外见闻与现代审美，中式题材维系乡土伦理与宗族认同，中西混搭则体现华侨“身在海外、根在开平”的双重文化认同。同时，开平建筑以灰塑、木雕、石雕等岭南工艺为基础，融入水泥、彩色玻璃等西方材料与技法，让传统工艺适配近代建筑形制，实现了传承与创新。而装饰亦兼顾防御、隔热、排水等功能需求与视觉审美，色彩适配气候特征，题材契合祈福、教化需求，践行“实用为本、审美为用”的岭南建筑哲学，实用了与审美的统一。</p><p>（二）艺术与历史价值</p><p>开平的碉楼与商用建筑开创了中西装饰融合的独特范式，灰塑、涂金木雕等工艺达到岭南巅峰，题材多元、色彩和谐，是近代中国建筑装饰艺术的高峰。这些建筑完整记录了19到20世纪开平华侨史、商贸史、建筑史，是研究近代中西文化交流、侨乡社会变迁的实物档案。</p><p>开平建筑装饰以中西元素深度融合、题材体系完整丰富、色彩运用理性适配为核心特征，通过立园、仓东村、塘口墟、赤坎古镇四类样本，展现出私家园林、古村祠堂、墟市建筑、商业骑楼的装饰差异与文化共性。其本质是近代华侨文化、岭南传统文化与西方工业文明碰撞融合的物质结晶，每一个装饰符号都是文化记忆的载体，既承载着华侨深厚的家国情怀，又展现出跨文化融合的艺术智慧。当前，开平建筑装饰面临自然风化、人为损毁、修复失准等问题，未来需加强灰塑、木雕等非遗工艺传承，推进建筑装饰数字化记录与精准修复，让这一独特文化遗产持续传递侨乡的历史底蕴与艺术魅力。</p><p>[1] 谭金花.开平碉楼与村落的建筑装饰研究[M].北京：中国建筑工业出版社，2008.</p><p>[2] 刘兴林.广东开平侨乡民国建筑装饰的特点与成因及其社会意义(1911-1949)[J].云南民族大学学报(哲学社会科学版), 2006(05):112-116.</p><p>[3] 开平市文化广电旅游体育局.广东省非物质文化遗产——开平灰雕[R].2023.</p><p>[4] 黄继涛.岭南侨乡建筑艺术研究——以开平碉楼与赤坎骑楼为例[J].美术观察，2019(08):142-143.</p><p>[5] 黄晓东.世界文化遗产——开平碉楼与村落[M].广州：广东人民出版社，2017.</p><p>[6] 黄玉书.开平碉楼的中西文化交融研究[D].广州：华南理工大学，2012.</p>',67)])])}const q=s(x,[["render",J]]);export{b as __pageData,q as default};
